# Collect all net names, keeping predefined IDs for the main power nets
_FIXED_NETS = ["GND", "VCC3V3", "VCC5V", "VBAT", "VUSB"]
_all_nets: list[str] = list(_FIXED_NETS)
for _pnets in NETLIST.values():
    for _n in _pnets.values():
        if _n not in _all_nets:
            _all_nets.append(_n)

# net_name -> integer ID used in (net N "name") expressions
NET_IDS: dict[str, int] = {name: i + 1 for i, name in enumerate(_all_nets)}

def u(): return str(uuid.uuid4())

