# ─── PCB helpers ────────────────────────────────────────────────────────────

def _replace_property(text, name, value):
    pat = re.compile(rf'\(\s*property\s+"{re.escape(name)}"\s+"[^"]*"', re.M)
    return pat.sub(f'(property "{name}" "{value}"', text, count=1)

def _insert_lcsc_property(text, lcsc):
    if not lcsc:
        return text
    prop = (f'\t(property "LCSC" "{lcsc}"\n'
            f'\t\t(at 0 0 0)\n'
            f'\t\t(layer "F.Fab")\n'
            f'\t\t(effects\n'
            f'\t\t\t(font\n'
            f'\t\t\t\t(size 1 1)\n'
            f'\t\t\t\t(thickness 0.15)\n'
            f'\t\t\t)\n'
            f'\t\t\t(hide yes)\n'
            f'\t\t)\n'
            f'\t)')
    value_match = re.search(r'\n\t\(property "Value".*?\n\t\)', text, re.S)
    if value_match:
        return text[:value_match.end()] + '\n' + prop + text[value_match.end():]
    return text.replace('\n\t(attr ', '\n' + prop + '\n\t(attr ', 1)

def _strip_drc_noise_layers(text):
    """Remove direct footprint items that create placement-only DRC noise."""
    first_nl = text.find('\n')
    head = text[:first_nl]
    body = text[first_nl + 1:text.rfind('\n)')]
    out = []
    start = None
    depth = 0
    for i, ch in enumerate(body):
        if ch == '(':
            if depth == 0:
                start = i
            depth += 1
        elif ch == ')':
            depth -= 1
            if depth == 0 and start is not None:
                item = body[start:i + 1]
                if item.lstrip().startswith('(property "Reference"'):
                    item = item.replace('(layer "F.SilkS")', '(layer "F.Fab")')
                    item = item.replace('(layer "B.SilkS")', '(layer "F.Fab")')
                    out.append(item)
                elif not any(layer in item for layer in ['(layer "F.SilkS")', '(layer "B.SilkS")',
                                                         '(layer "F.CrtYd")', '(layer "B.CrtYd")']):
                    out.append(item)
                start = None
    return head + '\n' + '\n'.join(out) + '\n)'

def inject_pad_nets(text: str, pad_nets: dict, net_ids: dict) -> str:
    """Inject (net N "name") into every pad block that has an assignment.

    Works on both single-line and multi-line pad S-expressions.
    """
    if not pad_nets:
        return text
    result: list[str] = []
    i = 0
    n = len(text)
    while i < n:
        m = re.search(r'\(pad ', text[i:])
        if m is None:
            result.append(text[i:])
            break
        result.append(text[i: i + m.start()])
        pad_start = i + m.start()
        # Walk to the matching closing paren
        depth = 0
        j = pad_start
        while j < n:
            if text[j] == '(':
                depth += 1
            elif text[j] == ')':
                depth -= 1
                if depth == 0:
                    j += 1
                    break
            j += 1
        block = text[pad_start:j]
        pm = re.match(r'\(pad "([^"]+)"', block)
        if pm:
            pad_num = pm.group(1)
            if pad_num in pad_nets:
                net_name = pad_nets[pad_num]
                nid = net_ids.get(net_name, 0)
                # Strip any existing (net ...) then append before closing paren
                block = re.sub(r'\s*\(net\s+\d+\s+"[^"]*"\)', '', block)
                block = block.rstrip()
                # Determine indent from the last line of the block
                last_nl = block.rfind('\n')
                indent = '\t\t' if last_nl == -1 else re.match(r'(\s*)', block[last_nl + 1:]).group(1)
                if block.endswith(')'):
                    block = block[:-1].rstrip() + f'\n{indent}(net {nid} "{net_name}")\n\t)'
        result.append(block)
        i = j
    return ''.join(result)


def fp(lib_ref, ref, val, x, y, layer='F.Cu', angle=0, lcsc='', pads=None):
    """Generate a board footprint with real library geometry when available."""
    pad_nets = NETLIST.get(ref, {})

    if pads:
        lines = [
            f'  (footprint "{lib_ref}" (layer "{layer}") (at {x:.3f} {y:.3f}{f" {angle}" if angle else ""})',
            f'    (descr "{val}")',
            f'    (tags "")',
            f'    (property "Reference" "{ref}" (at 0 -3 0) (layer "F.SilkS")',
            f'      (effects (font (size 1 1))))',
            f'    (property "Value" "{val}" (at 0 3 0) (layer "F.Fab")',
            f'      (effects (font (size 1 1))))',
        ]
        if lcsc:
            lines.append(f'    (property "LCSC" "{lcsc}" (at 0 0 0) (layer "F.Fab")')
            lines.append(f'      (effects (font (size 1 1)) (hide yes)))')
        lines.extend(pads)
        lines.append(f'  )')
        text = '\n'.join(lines)
        return inject_pad_nets(text, pad_nets, NET_IDS)

    lib, name = lib_ref.split(':', 1)
    mod_path = Path('/usr/share/kicad/footprints') / f'{lib}.pretty' / f'{name}.kicad_mod'
    if not mod_path.exists():
        raise FileNotFoundError(f"Footprint not found: {lib_ref} ({mod_path})")

    lines = [
        line for line in mod_path.read_text().splitlines()
        if not re.match(r'\s*\((version|generator|generator_version|embedded_fonts)\b', line)
    ]
    lines[0] = f'  (footprint "{lib_ref}"'
    at = f'\t(at {x:.3f} {y:.3f}{f" {angle}" if angle else ""})'
    lines.insert(1, at)
    text = '\n'.join(lines)
    text = _replace_property(text, 'Reference', ref)
    text = _replace_property(text, 'Value', val)
    text = _insert_lcsc_property(text, lcsc)
    text = _strip_drc_noise_layers(text)
    return inject_pad_nets(text, pad_nets, NET_IDS)

def simple_switch_pads():
    return [
        '    (fp_rect (start -3.2 -3.2) (end 3.2 3.2) (stroke (width 0.1) (type solid)) (fill no) (layer "F.Fab"))',
        '    (pad "1" smd rect (at -2.25 0) (size 1.5 3.0) (layers "F.Cu" "F.Paste" "F.Mask"))',
        '    (pad "2" smd rect (at 2.25 0) (size 1.5 3.0) (layers "F.Cu" "F.Paste" "F.Mask"))',
    ]

def rect_pad(num, x, y, w, h, layer='F.Cu', drill=None):
    shape = 'roundrect' if not drill else 'circle'
    dstr = f' (drill {drill:.2f})' if drill else ''
    return (f'    (pad "{num}" {"thru_hole" if drill else "smd"} rect'
            f' (at {x:.3f} {y:.3f}) (size {w:.3f} {h:.3f})'
            f' (layers "{layer}" "*.Cu"){dstr})')

def circ_pad(num, x, y, d, drill=None):
    dstr = f' (drill {drill:.2f})' if drill else ''
    layers = '"*.Cu" "*.Mask"' if drill else f'"F.Cu" "F.Mask"'
    return (f'    (pad "{num}" {"thru_hole" if drill else "smd"} circle'
            f' (at {x:.3f} {y:.3f}) (size {d:.3f} {d:.3f})'
            f' (layers {layers}){dstr})')

def via(x, y, drill=0.4, size=0.8, net_id=0, net_name=''):
    net_field = f' (net {net_id})' if net_id else ''
    return (f'  (via (at {x:.3f} {y:.3f}) (size {size:.3f}) (drill {drill:.3f})'
            f' (layers "F.Cu" "B.Cu"){net_field} (uuid "{u()}"))')

def power_plane_stitching_vias(pcb_text):
    """Find every pad on a power net and emit a stitching via at its center.
    This lets freerouting treat those pads as already-connected through the
    inner plane, removing them from the routing problem."""
    import math as _m
    power_nets = {'GND', 'VCC3V3', 'VCC5V'}
    vias = []
    seen = set()
    # Walk footprint blocks
    pos = [p.start() for p in re.finditer(r'\(footprint\s+"', pcb_text)]
    pos.append(len(pcb_text))
    for a, b in zip(pos[:-1], pos[1:]):
        blk = pcb_text[a:b]
        am = re.search(r'\n\s*\(at\s+([\d.\-]+)\s+([\d.\-]+)(?:\s+([\d.\-]+))?', blk)
        if not am: continue
        fx, fy = float(am.group(1)), float(am.group(2))
        fang = float(am.group(3)) if am.group(3) else 0.0
        ca, sa = _m.cos(_m.radians(fang)), _m.sin(_m.radians(fang))
        # walk pads
        ppos = [p.start() for p in re.finditer(r'\(pad\s+"', blk)]
        ppos.append(len(blk))
        for pa, pb in zip(ppos[:-1], ppos[1:]):
            pblk = blk[pa:pb]
            am2 = re.search(r'\(at\s+([\d.\-]+)\s+([\d.\-]+)', pblk)
            nm = re.search(r'\(net\s+(\d+)\s+"([^"]*)"\)', pblk)
            if not (am2 and nm): continue
            net_id = int(nm.group(1)); net_name = nm.group(2)
            if net_name not in power_nets: continue
            px, py = float(am2.group(1)), float(am2.group(2))
            wx = fx + px*ca - py*sa
            wy = fy + px*sa + py*ca
            key = (round(wx, 2), round(wy, 2))
            if key in seen: continue
            seen.add(key)
            vias.append(via(wx, wy, drill=0.3, size=0.6,
                            net_id=net_id, net_name=net_name))
    return vias

def track(x1,y1,x2,y2, width=0.25, layer='F.Cu'):
    return (f'  (segment (start {x1:.3f} {y1:.3f}) (end {x2:.3f} {y2:.3f})'
            f' (width {width:.3f}) (layer "{layer}") (uuid "{u()}"))')

def zone(net_name, layer, pts, min_thk=0.25, priority=0):
    """Copper zone/pour"""
    pt_str = ' '.join(f'(xy {x:.3f} {y:.3f})' for x,y in pts)
    nid = NET_IDS.get(net_name, 0)
    prio = f'(priority {priority}) ' if priority else ''
    return f'''  (zone (net {nid}) (net_name "{net_name}") (layer "{layer}") (uuid "{u()}")
    {prio}(connect_pads (clearance 0.3))
    (min_thickness {min_thk:.3f}) (filled_areas_thickness no)
    (fill yes (thermal_gap 0.5) (thermal_bridge_width 0.3))
    (polygon (pts {pt_str}))
  )'''

def edge(x1,y1,x2,y2):
    return (f'  (gr_line (start {x1:.3f} {y1:.3f}) (end {x2:.3f} {y2:.3f})'
            f' (layer "Edge.Cuts") (width 0.05) (uuid "{u()}"))')

def silk_text(txt, x, y, layer='F.SilkS', size=1.0):
    return (f'  (gr_text "{txt}" (at {x:.3f} {y:.3f}) (layer "{layer}")'
            f' (effects (font (size {size} {size}) (thickness 0.15))))')

