vcc3v3_zone_i1 = zone("VCC3V3","In1.Cu",[(1,1),(W-1,1),(W-1,H-1),(1,H-1)])
vcc5v_zone_i1 = zone("VCC5V","In1.Cu", [(1,1),(30,1),(30,45),(1,45)], priority=2)
gnd_zone_i2 = zone("GND","In2.Cu",[(1,1),(W-1,1),(W-1,H-1),(1,H-1)])
power_pours = [vcc3v3_zone_i1, vcc5v_zone_i1, gnd_zone_i2]

# ─── Generate PCB ─────────────────────────────────────────────────────────────

STACKUP = '''  (setup
    (stackup
      (layer "F.SilkS" (type "Top Silk Screen"))
      (layer "F.Paste" (type "Top Solder Paste"))
      (layer "F.Mask" (type "Top Solder Mask") (thickness 0.01))
      (layer "F.Cu" (type "copper") (thickness 0.035))
      (layer "dielectric 1" (type "prepreg") (thickness 0.2104) (material "FR4") (epsilon_r 4.5) (loss_tangent 0.02))
      (layer "In1.Cu" (type "copper") (thickness 0.0152))
      (layer "dielectric 2" (type "core") (thickness 1.065) (material "FR4") (epsilon_r 4.5) (loss_tangent 0.02))
      (layer "In2.Cu" (type "copper") (thickness 0.0152))
      (layer "dielectric 3" (type "prepreg") (thickness 0.2104) (material "FR4") (epsilon_r 4.5) (loss_tangent 0.02))
      (layer "B.Cu" (type "copper") (thickness 0.035))
      (layer "B.Mask" (type "Bottom Solder Mask") (thickness 0.01))
      (layer "B.Paste" (type "Bottom Solder Paste"))
      (layer "B.SilkS" (type "Bottom Silk Screen"))
      (copper_finish "ENIG")
      (dielectric_constraints no)
    )
    (pad_to_mask_clearance 0.05)
    (solder_mask_min_width 0)
    (pad_to_paste_clearance 0)
    (pad_to_paste_clearance_ratio 0)
    (allow_soldermask_bridges_in_footprints no)
  )'''

pcb = ['(kicad_pcb (version 20230121) (generator pcbnew)',
       '  (general (thickness 1.6) (legacy_teardrops no))',
       '  (paper "A3")',
       f'  (title_block (title "ArtNet LED Controller")(rev "1.0")(company "Open Source"))',
       '',
       '  (layers',
       '    (0 "F.Cu" signal)',
       '    (1 "In1.Cu" power)',
       '    (2 "In2.Cu" power)',
       '    (31 "B.Cu" signal)',
       '    (32 "B.Adhes" user)',
       '    (33 "F.Adhes" user)',
       '    (34 "B.Paste" user)',
       '    (35 "F.Paste" user)',
       '    (36 "B.SilkS" user)',
       '    (37 "F.SilkS" user)',
       '    (38 "B.Mask" user)',
       '    (39 "F.Mask" user)',
       '    (40 "Dwgs.User" user)',
       '    (41 "Cmts.User" user)',
       '    (44 "Edge.Cuts" user)',
       '    (45 "Margin" user)',
       '    (46 "B.CrtYd" user)',
       '    (47 "F.CrtYd" user)',
       '    (48 "B.Fab" user)',
       '    (49 "F.Fab" user)',
       '  )',
       '',
       STACKUP,
       '',
       '  (net 0 "")',
       *[f'  (net {NET_IDS[n]} "{n}")' for n in _all_nets],
       '',
       ]

# Add board outline
pcb.extend(edges)

# Add mounting holes
pcb.extend(mholes)

# Silk labels
pcb.extend(silks)

# Add footprints
pcb.extend(footprints)

# Add copper pours
for _pour in power_pours:
    pcb.append(_pour)

# Power-plane stitching vias: DISABLED — let freerouting place its own vias.
# Pre-injected stitching vias clogged escape paths on the tight F.Cu area.
_plane_vias = []

# Closing
pcb.append(')')

out = '\n'.join(pcb)
print(f"  + {len(_plane_vias)} plane-stitching vias on power pads")
pcb_path = DIR / f"{PROJ}.kicad_pcb"
with open(pcb_path,'w') as f:
    f.write(out)
print(f"PCB written: {pcb_path} ({len(out):,} bytes)")
